const https = require('https');

const AMBIENTES = [
  {
    nombre: 'Dev',
    tag:    'DEV',
    url:    'https://dev.portalpaciente.bupa.cl/login',
    color:  '#1565C0'
  },
  {
    nombre: 'Staging / UAT',
    tag:    'STG/UAT',
    url:    'https://staging.portalpaciente.bupa.cl/login',
    color:  '#6A1B9A'
  },
  {
    nombre: 'Producción',
    tag:    'PROD',
    url:    'https://portalpaciente.bupa.cl/login',
    color:  '#1B5E20'
  }
];

async function checkUrl(url) {
  return new Promise((resolve) => {
    const timer = setTimeout(() => resolve({ ok: false, status: 0, error: 'Timeout (8s)' }), 8000);
    try {
      const req = https.get(url, { headers: { 'User-Agent': 'n8n-health-check-wf15' } }, (res) => {
        clearTimeout(timer);
        resolve({ ok: res.statusCode < 400, status: res.statusCode, error: null });
        res.resume();
      });
      req.on('error', (e) => { clearTimeout(timer); resolve({ ok: false, status: 0, error: e.message }); });
      req.on('timeout', ()  => { clearTimeout(timer); req.destroy(); resolve({ ok: false, status: 0, error: 'Timeout' }); });
    } catch(e) {
      clearTimeout(timer);
      resolve({ ok: false, status: 0, error: e.message });
    }
  });
}

// Verificar los 3 ambientes en paralelo
const checks = await Promise.all(AMBIENTES.map(async (amb) => {
  const result = await checkUrl(amb.url);
  return { ...amb, ...result };
}));

const totalOk    = checks.filter(c => c.ok).length;
const totalDown  = checks.filter(c => !c.ok).length;
const todosOk    = totalDown === 0;

// Fecha/hora Chile
const ahora      = new Date();
const hora       = ahora.toLocaleTimeString('es-CL', { timeZone: 'America/Santiago', hour: '2-digit', minute: '2-digit' });
const dd         = String(ahora.getDate()).padStart(2, '0');
const mm         = String(ahora.getMonth() + 1).padStart(2, '0');
const yyyy       = ahora.getFullYear();
const fechaCorta = `${dd}-${mm}-${yyyy}`;
const fechaLarga = ahora.toLocaleDateString('es-CL', { timeZone: 'America/Santiago', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

// Colores globales según estado
const COLOR_HEADER = todosOk ? '#1B5E20' : '#B71C1C';
const COLOR_GRAD   = todosOk
  ? 'linear-gradient(135deg,#1B5E20 0%,#2E7D32 100%)'
  : 'linear-gradient(135deg,#B71C1C 0%,#C62828 100%)';
const ICON_ESTADO  = todosOk ? '✅' : '🔴';
const TEXTO_ESTADO = todosOk ? 'TODOS LOS AMBIENTES OPERATIVOS' : `${totalDown} AMBIENTE(S) CAÍDO(S)`;

// Filas de la tabla
const filas = checks.map(c => {
  const ok       = c.ok;
  const bgRow    = ok ? '#F1F8E9' : '#FFEBEE';
  const badgeBg  = ok ? '#E8F5E9' : '#FFCDD2';
  const badgeClr = ok ? '#2E7D32' : '#C62828';
  const icono    = ok ? '🟢' : '🔴';
  const estado   = ok ? 'UP' : 'DOWN';
  const statusTx = c.status > 0 ? `HTTP ${c.status}` : (c.error || 'Sin respuesta');
  return `
  <tr style="background:${bgRow};border-bottom:1px solid #E0E0E0">
    <td style="padding:12px 14px;font-weight:bold;font-size:13px;color:#212121">${c.nombre}</td>
    <td style="padding:12px 14px;font-size:11px;color:#546E7A;word-break:break-all">${c.url}</td>
    <td style="padding:12px 14px;text-align:center">
      <span style="background:${badgeBg};color:${badgeClr};padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold">${icono} ${estado}</span>
    </td>
    <td style="padding:12px 14px;text-align:center;font-size:11px;color:#546E7A">${statusTx}</td>
  </tr>`;
}).join('');

const htmlEmail = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#F5F5F5;font-family:Arial,sans-serif">
<div style="max-width:680px;margin:20px auto;background:white;border-radius:12px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,0.12)">

  <!-- HEADER -->
  <div style="background:${COLOR_GRAD};padding:28px 32px">
    <div style="display:flex;justify-content:space-between;align-items:center">
      <div>
        <div style="color:rgba(255,255,255,0.8);font-size:11px;font-weight:bold;letter-spacing:2px;text-transform:uppercase">QUALITY ASSURANCE</div>
        <div style="color:white;font-size:22px;font-weight:bold;margin-top:4px">🌐 Health Check — Ambientes QA</div>
        <div style="color:rgba(255,255,255,0.85);font-size:12px;margin-top:3px">BUPA Portal Pacientes — Validación automática</div>
      </div>
      <div style="background:rgba(255,255,255,0.15);border-radius:10px;padding:14px 18px;text-align:center">
        <div style="color:white;font-size:28px">${ICON_ESTADO}</div>
        <div style="color:rgba(255,255,255,0.9);font-size:9px;margin-top:4px;font-weight:bold">${todosOk ? 'ALL OK' : 'ALERTA'}</div>
      </div>
    </div>
    <div style="color:rgba(255,255,255,0.8);font-size:11px;margin-top:16px;border-top:1px solid rgba(255,255,255,0.2);padding-top:12px">
      📅 ${fechaLarga.charAt(0).toUpperCase() + fechaLarga.slice(1)}  •  🕐 ${hora} hrs  •  QA Lead: Jaime Quiñelen
    </div>
  </div>

  <!-- BANNER ESTADO -->
  <div style="background:${todosOk ? '#E8F5E9' : '#FFEBEE'};padding:14px 32px;border-bottom:3px solid ${todosOk ? '#2E7D32' : '#C62828'}">
    <div style="font-size:14px;font-weight:bold;color:${todosOk ? '#1B5E20' : '#B71C1C'};text-align:center">
      ${ICON_ESTADO} ${TEXTO_ESTADO}
    </div>
  </div>

  <!-- KPI CARDS -->
  <div style="padding:20px 32px 8px">
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px">
      <div style="background:#E3F2FD;border-radius:8px;padding:14px;border-left:4px solid #1976D2;text-align:center">
        <div style="font-size:28px;font-weight:bold;color:#1976D2">${checks.length}</div>
        <div style="font-size:10px;color:#0D47A1;font-weight:bold;margin-top:2px">AMBIENTES</div>
      </div>
      <div style="background:#E8F5E9;border-radius:8px;padding:14px;border-left:4px solid #2E7D32;text-align:center">
        <div style="font-size:28px;font-weight:bold;color:#2E7D32">${totalOk}</div>
        <div style="font-size:10px;color:#1B5E20;font-weight:bold;margin-top:2px">OPERATIVOS</div>
      </div>
      <div style="background:${totalDown > 0 ? '#FFEBEE' : '#F5F5F5'};border-radius:8px;padding:14px;border-left:4px solid ${totalDown > 0 ? '#C62828' : '#9E9E9E'};text-align:center">
        <div style="font-size:28px;font-weight:bold;color:${totalDown > 0 ? '#C62828' : '#9E9E9E'}">${totalDown}</div>
        <div style="font-size:10px;color:${totalDown > 0 ? '#B71C1C' : '#757575'};font-weight:bold;margin-top:2px">CAÍDOS</div>
      </div>
    </div>
  </div>

  <!-- TABLA AMBIENTES -->
  <div style="padding:16px 32px 24px">
    <div style="font-size:13px;font-weight:bold;color:#0D47A1;margin-bottom:10px">📋 Detalle por Ambiente</div>
    <table style="width:100%;border-collapse:collapse;font-size:13px;border-radius:8px;overflow:hidden">
      <thead>
        <tr style="background:#0D47A1">
          <th style="padding:10px 14px;text-align:left;color:white;font-size:11px;width:130px">Ambiente</th>
          <th style="padding:10px 14px;text-align:left;color:white;font-size:11px">URL</th>
          <th style="padding:10px 14px;text-align:center;color:white;font-size:11px;width:100px">Estado</th>
          <th style="padding:10px 14px;text-align:center;color:white;font-size:11px;width:100px">HTTP</th>
        </tr>
      </thead>
      <tbody>${filas}</tbody>
    </table>
  </div>

  <!-- NOTA Dev/Staging -->
  ${!todosOk ? `<div style="margin:0 32px 20px;background:#FFF8E1;border-radius:8px;padding:12px 16px;border-left:4px solid #F9A825">
    <div style="font-size:11px;color:#E65100"><b>ℹ️ Nota:</b> Dev y Staging/UAT usan URLs ficticias de prueba — se espera que estén caídos en este entorno.</div>
  </div>` : ''}

  <!-- FOOTER -->
  <div style="background:#0D47A1;padding:16px 32px;text-align:center">
    <div style="color:#90CAF9;font-size:11px">Generado por <b style="color:white">WF-1.5 Health Check QA</b> — n8n  •  BUPA Chile</div>
    <div style="color:#64B5F6;font-size:10px;margin-top:4px">Próxima verificación automática en 1 hora  •  ${fechaCorta}  •  ${hora} hrs</div>
  </div>

</div></body></html>`;

const asunto = todosOk
  ? `✅ [WF-1.5] Ambientes QA — TODOS OK — ${fechaCorta} ${hora}`
  : `🔴 [WF-1.5] Ambientes QA — ${totalDown} CAÍDO(S) — ${fechaCorta} ${hora}`;

return [{ json: {
  emailPayload: { to: 'jaimeqv.2609@gmail.com', subject: asunto, html: htmlEmail },
  resumen: { totalOk, totalDown, todosOk, checks: checks.map(c => ({ nombre: c.nombre, ok: c.ok, status: c.status })) }
}}];
